def solve(grid):
    grid = [row[:] for row in grid]
    H, W = len(grid), len(grid[0])

    special = {}
    for r in range(H):
        for c in range(W):
            if grid[r][c] not in (0, 1):
                special[(r, c)] = grid[r][c]

    dirs = [(-1,-1), (-1,1), (1,-1), (1,1)]

    # Find connected components via diagonal adjacency
    visited = set()
    diamonds = []
    for pos in special:
        if pos in visited:
            continue
        component = set()
        queue = [pos]
        visited.add(pos)
        while queue:
            p = queue.pop(0)
            component.add(p)
            for dr, dc in dirs:
                n = (p[0]+dr, p[1]+dc)
                if n in special and n not in visited:
                    visited.add(n)
                    queue.append(n)
        diamonds.append(component)

    for diamond in diamonds:
        color_groups = {}
        for pos in diamond:
            c = special[pos]
            color_groups.setdefault(c, set()).add(pos)

        # Find ring color: each cell has exactly 2 same-color diagonal neighbors
        ring_color = None
        for color, cells in color_groups.items():
            if len(cells) < 4:
                continue
            all_two = True
            for r, c in cells:
                count = sum(1 for dr, dc in dirs if (r+dr, c+dc) in cells)
                if count != 2:
                    all_two = False
                    break
            if all_two:
                ring_color = color
                break

        if ring_color is None:
            continue

        ring_set = color_groups[ring_color]

        for color, cells in color_groups.items():
            if color == ring_color:
                continue
            for r, c in cells:
                same_count = sum(1 for dr, dc in dirs if (r+dr, c+dc) in cells)
                if same_count <= 1:  # endpoint
                    for dr, dc in dirs:
                        if (r+dr, c+dc) in ring_set:
                            ray_dr, ray_dc = -dr, -dc
                            nr, nc = r + ray_dr, c + ray_dc
                            while 0 <= nr < H and 0 <= nc < W:
                                if grid[nr][nc] in (0, 1):
                                    grid[nr][nc] = color
                                nr += ray_dr
                                nc += ray_dc
                            break

    return grid

